    public List<DebtOffsetEventResponse> getDebtOffsetEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(DEBTOFFSET_EVENT, transactionReceipt);
        ArrayList<DebtOffsetEventResponse> responses = new ArrayList<DebtOffsetEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            DebtOffsetEventResponse typedResponse = new DebtOffsetEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.sourceReceivableId = (byte[]) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.targetReceivableId = (byte[]) eventValues.getIndexedValues().get(1).getValue();
            typedResponse.operator = (String) eventValues.getIndexedValues().get(2).getValue();
            typedResponse.offsetAmount = (BigInteger) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

